const tree = $input.first().json.tree;

const repo = "gitlab_rag_leave_policy_source";
const owner = "M-Longoria";
const sourceBranch = "main";

// The file tree node's top-level sha is the commit/tree-ish SHA
// used to fetch this exact repository snapshot.
const commitSha = $input.first().json.sha;

if (!tree || !Array.isArray(tree)) {
  throw new Error("GitHub tree not found or invalid");
}

if (!commitSha) {
  throw new Error("Commit SHA not found");
}

const repoBase =
  "https://raw.githubusercontent.com/" + owner + "/" + repo + "/" + commitSha + "/";

const mdFiles = tree
  .filter(item =>
    item.type === "blob" &&
    item.path &&
    item.path.endsWith(".md")
  )
  .map(item => {
    const cleanPath = item.path.replace(/\\/g, "/");

    return {
      json: {
        document_id: repo + "/" + cleanPath,
        file_path: cleanPath,
        source_url: repoBase + cleanPath,
        file_type: "markdown",
        repo,
        source_branch: sourceBranch,
        commit_sha: commitSha,
        blob_sha: item.sha
      }
    };
  });

return mdFiles;

// ------------------------------------------------------------
// 1. Decode common HTML entities
// ------------------------------------------------------------
// GitHub/raw Markdown can sometimes contain HTML entities.
// This converts the most common ones back into normal characters.
function decodeHtmlEntities(text) {
  return text
    .replace(/&#x26;/g, "&")
    .replace(/&#39;/g, "'")
    .replace(/&quot;/g, '"')
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">");
}

// ------------------------------------------------------------
// 2. Normalize escaped Markdown characters
// ------------------------------------------------------------
// Some Markdown exports escape punctuation like \# or \-.
// This removes unnecessary backslashes while keeping the visible text.
function normalizeEscapedMarkdown(text) {
  return text
    .replace(/\\#/g, "#")
    .replace(/\\\*/g, "*")
    .replace(/\\_/g, "_")
    .replace(/\\-/g, "-")
    .replace(/\\\+/g, "+")
    .replace(/\\\./g, ".")
    .replace(/\\!/g, "!")
    .replace(/\\\[/g, "[")
    .replace(/\\\]/g, "]")
    .replace(/\\\(/g, "(")
    .replace(/\\\)/g, ")")
    .replace(/\\`/g, "`");
}

// ------------------------------------------------------------
// 3. Normalize whitespace and line endings
// ------------------------------------------------------------
// Converts Windows line endings to standard newlines,
// reduces excessive blank lines, and trims the document edges.
function normalizeWhitespace(text) {
  return text
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .replace(/[ \t]+$/gm, "")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

// ------------------------------------------------------------
// 4. Remove obvious low-value noise
// ------------------------------------------------------------
// Keep this conservative. For RAG, deleting too much text early
// can remove useful retrieval clues.
function removeNoise(text) {
  return text
    .replace(/_Last modified.*$/gm, "");
}

// ------------------------------------------------------------
// 5. Process each incoming n8n item
// ------------------------------------------------------------
// Each item represents one Markdown file. We keep the original
// raw_text and add clean_text for downstream chunking/embedding.
return items.map(i => {
  let text = i.json.raw_text || "";

  text = decodeHtmlEntities(text);
  text = normalizeEscapedMarkdown(text);
  text = normalizeWhitespace(text);
  text = removeNoise(text);

  return {
    json: {
      document_id: i.json.document_id,
      file_path: i.json.file_path,
      source_url: i.json.source_url,
      repo: i.json.repo,
      file_type: i.json.file_type,
      source_branch: i.json.source_branch,
      commit_sha: i.json.commit_sha,
      blob_sha: i.json.blob_sha,
      raw_text: i.json.raw_text,
      clean_text: text,
      clean_char_count: text.length,
      has_content: text.trim().length > 0,
      ingestion_status: "cleaned"
    }
  };
});

const TARGET_WORDS = 450;
const MAX_WORDS = 800;
const OVERLAP_BLOCKS = 1;
const MIN_WORDS = 20;

function getMarkdownHeading(line) {
  let level = 0;

  while (level < line.length && level < 6 && line.charAt(level) === "#") {
    level++;
  }

  if (level === 0) return null;
  if (line.charAt(level) !== " ") return null;

  const title = line.slice(level + 1).trim();

  if (!title) return null;

  return {
    level,
    title,
    source: "markdown_heading"
  };
}

function getHeadingPath(path) {
  return path.map(p => p.title).join(" > ");
}

function countWords(text) {
  return text
    .split(" ")
    .map(word => word.trim())
    .filter(Boolean)
    .length;
}

function getFirstMeaningfulLine(text) {
  const lines = text.split("\n");

  for (const line of lines) {
    const trimmed = line.trim();

    if (trimmed) {
      return trimmed;
    }
  }

  return "Untitled";
}

function inferTitleFromText(text) {
  const firstLine = getFirstMeaningfulLine(text);

  if (firstLine.length <= 120) {
    return firstLine;
  }

  return firstLine.slice(0, 117).trim() + "...";
}

function splitIntoBlocks(text) {
  const lines = text.split("\n");
  const blocks = [];
  let current = [];

  for (const line of lines) {
    if (line.trim() === "") {
      if (current.length > 0) {
        blocks.push(current.join("\n").trim());
        current = [];
      }
    } else {
      current.push(line);
    }
  }

  if (current.length > 0) {
    blocks.push(current.join("\n").trim());
  }

  return blocks;
}

function splitLongTextByBlocks(text) {
  const blocks = splitIntoBlocks(text);

  if (countWords(text) <= MAX_WORDS) {
    return [text];
  }

  const chunks = [];
  let currentBlocks = [];
  let currentWords = 0;

  for (const block of blocks) {
    const blockWords = countWords(block);

    if (currentWords > 0 && currentWords + blockWords > TARGET_WORDS) {
      chunks.push(currentBlocks.join("\n\n"));

      const overlap = currentBlocks.slice(-OVERLAP_BLOCKS);
      currentBlocks = overlap.slice();
      currentWords = countWords(currentBlocks.join("\n\n"));
    }

    currentBlocks.push(block);
    currentWords += blockWords;
  }

  if (currentBlocks.length > 0) {
    chunks.push(currentBlocks.join("\n\n"));
  }

  return chunks;
}

function splitMarkdownSections(text) {
  const lines = text.split("\n");
  const sections = [];

  let headingPath = [];
  let currentSection = null;

  for (const line of lines) {
    const heading = getMarkdownHeading(line);

    if (heading) {
      if (currentSection && currentSection.lines.join("\n").trim()) {
        sections.push({
          title: currentSection.title,
          header_level: currentSection.header_level,
          heading_path: currentSection.heading_path,
          heading_source: currentSection.heading_source,
          section_text: currentSection.lines.join("\n").trim()
        });
      }

      headingPath = headingPath.filter(h => h.level < heading.level);
      headingPath.push(heading);

      currentSection = {
        title: heading.title,
        header_level: heading.level,
        heading_path: getHeadingPath(headingPath),
        heading_source: heading.source,
        lines: [line]
      };
    } else if (currentSection) {
      currentSection.lines.push(line);
    } else if (line.trim()) {
      const inferredTitle = inferTitleFromText(line);

      currentSection = {
        title: inferredTitle,
        header_level: 0,
        heading_path: inferredTitle,
        heading_source: "inferred_first_line",
        lines: [line]
      };
    }
  }

  if (currentSection && currentSection.lines.join("\n").trim()) {
    sections.push({
      title: currentSection.title,
      header_level: currentSection.header_level,
      heading_path: currentSection.heading_path,
      heading_source: currentSection.heading_source,
      section_text: currentSection.lines.join("\n").trim()
    });
  }

  return sections;
}

function isStepSection(section) {
  const title = (section.title || "").toLowerCase();

  return (
    title.startsWith("step ") ||
    title.startsWith("step:")
  );
}

function getParentHeadingPath(section) {
  const parts = (section.heading_path || "").split(" > ");

  if (parts.length <= 1) {
    return section.heading_path;
  }

  return parts.slice(0, -1).join(" > ");
}

function groupProcedureSteps(sections) {
  const grouped = [];
  let buffer = [];

  function flushBuffer() {
    if (buffer.length === 0) return;

    if (buffer.length === 1) {
      grouped.push(buffer[0]);
      buffer = [];
      return;
    }

    const first = buffer[0];
    const parentPath = getParentHeadingPath(first);
    const parentTitle = parentPath.split(" > ").pop() || first.title;
    const combinedText = buffer.map(s => s.section_text).join("\n\n");

    grouped.push({
      title: parentTitle,
      header_level: Math.max(first.header_level - 1, 0),
      heading_path: parentPath,
      heading_source: "grouped_procedure_steps",
      section_text: combinedText,
      grouped_section_count: buffer.length,
      grouped_section_titles: buffer.map(s => s.title)
    });

    buffer = [];
  }

  for (const section of sections) {
    if (isStepSection(section)) {
      buffer.push(section);
    } else {
      flushBuffer();
      grouped.push(section);
    }
  }

  flushBuffer();

  return grouped;
}

function sectionToChunks(section) {
  const sectionWordCount = countWords(section.section_text);

  if (sectionWordCount < MIN_WORDS) {
    return [{
      text: section.section_text,
      split_reason: "small_section",
      section_chunk_index: 0
    }];
  }

  const chunkTexts = splitLongTextByBlocks(section.section_text);

  return chunkTexts.map((text, index) => ({
    text,
    split_reason: chunkTexts.length > 1 ? "oversized_section_split" : "section_boundary",
    section_chunk_index: index
  }));
}

return items.flatMap(i => {
  const cleanText = i.json.clean_text || "";

  if (!cleanText.trim()) {
    return [];
  }

  const sections = groupProcedureSteps(splitMarkdownSections(cleanText));
  const output = [];
  let chunkIndex = 0;

  for (const section of sections) {
    const sectionChunks = sectionToChunks(section);

    for (const sectionChunk of sectionChunks) {
      const chunkText = sectionChunk.text.trim();

      if (!chunkText) continue;

      output.push({
        json: {
          chunk_id: i.json.document_id + "#chunk-" + chunkIndex,
          document_id: i.json.document_id,
          chunk_index: chunkIndex,

          file_path: i.json.file_path,
          source_url: i.json.source_url,
          repo: i.json.repo,
          file_type: i.json.file_type,
          source_branch: i.json.source_branch,
          commit_sha: i.json.commit_sha,
          blob_sha: i.json.blob_sha,

          title: section.title,
          header_level: section.header_level,
          heading_path: section.heading_path,
          heading_source: section.heading_source,

          chunk_text: chunkText,
          chunk_char_count: chunkText.length,
          chunk_word_count: countWords(chunkText),

          split_reason: section.grouped_section_count
            ? sectionChunk.split_reason + "+grouped_procedure_steps"
            : sectionChunk.split_reason,
          section_chunk_index: sectionChunk.section_chunk_index ?? 0,
          grouped_section_count: section.grouped_section_count || 0,
          grouped_section_titles: section.grouped_section_titles || [],

          ingestion_status: i.json.ingestion_status,
          chunk_status: "chunked"
        }
      });

      chunkIndex++;
    }
  }

  return output;
});

const chunks = items.map(i => i.json);

const totalChunks = chunks.length;

const tinyChunks = chunks.filter(c => c.chunk_word_count < 20);
const smallChunks = chunks.filter(c => c.chunk_word_count >= 20 && c.chunk_word_count < 50);
const mediumChunks = chunks.filter(c => c.chunk_word_count >= 50 && c.chunk_word_count <= 800);
const largeChunks = chunks.filter(c => c.chunk_word_count > 800);

const oversizedSplits = chunks.filter(c => c.split_reason === "oversized_section_split");
const smallSections = chunks.filter(c => c.split_reason === "small_section");
const untitledChunks = chunks.filter(c => c.title === "Untitled" || c.heading_path === "Untitled");

function average(numbers) {
  if (numbers.length === 0) return 0;

  const total = numbers.reduce((sum, value) => sum + value, 0);
  return Math.round(total / numbers.length);
}

function getExamples(list, limit) {
  return list.slice(0, limit).map(c => ({
    chunk_id: c.chunk_id,
    file_path: c.file_path,
    title: c.title,
    heading_path: c.heading_path,
    chunk_word_count: c.chunk_word_count,
    split_reason: c.split_reason,
    preview: c.chunk_text.slice(0, 250)
  }));
}

const wordCounts = chunks.map(c => c.chunk_word_count);

return [{
  json: {
    total_chunks: totalChunks,

    avg_chunk_word_count: average(wordCounts),
    min_chunk_word_count: Math.min(...wordCounts),
    max_chunk_word_count: Math.max(...wordCounts),

    tiny_chunks_under_20: tinyChunks.length,
    small_chunks_20_to_49: smallChunks.length,
    medium_chunks_50_to_800: mediumChunks.length,
    large_chunks_over_800: largeChunks.length,

    oversized_section_splits: oversizedSplits.length,
    small_sections: smallSections.length,
    untitled_chunks: untitledChunks.length,

    tiny_chunk_examples: getExamples(tinyChunks, 5),
    large_chunk_examples: getExamples(largeChunks, 5),
    untitled_chunk_examples: getExamples(untitledChunks, 5)
  }
}];

const MIN_WORDS = 20;

function countWords(text) {
  return text
    .split(" ")
    .map(word => word.trim())
    .filter(Boolean)
    .length;
}

function getMarkdownHeading(line) {
  let level = 0;

  while (level < line.length && level < 6 && line.charAt(level) === "#") {
    level++;
  }

  if (level === 0) return null;
  if (line.charAt(level) !== " ") return null;

  const title = line.slice(level + 1).trim();

  if (!title) return null;

  return {
    level,
    title
  };
}

function looksLikeHeadingOnly(text) {
  const lines = text
    .split("\n")
    .map(line => line.trim())
    .filter(Boolean);

  if (lines.length !== 1) {
    return false;
  }

  return getMarkdownHeading(lines[0]) !== null;
}

function mergeDocumentChunks(chunks) {
  const merged = [];

  for (let index = 0; index < chunks.length; index++) {
    const chunk = chunks[index];
    const wordCount = countWords(chunk.chunk_text);
    const headingOnly = looksLikeHeadingOnly(chunk.chunk_text);

    const shouldMerge =
      wordCount < MIN_WORDS ||
      headingOnly ||
      chunk.split_reason === "small_section";

    if (!shouldMerge) {
      merged.push({
        ...chunk,
        merged_small_section_count: chunk.merged_small_section_count || 0,
        merged_small_section_titles: chunk.merged_small_section_titles || []
      });
      continue;
    }

    if (headingOnly && index + 1 < chunks.length) {
      const nextChunk = chunks[index + 1];

      nextChunk.chunk_text = chunk.chunk_text + "\n\n" + nextChunk.chunk_text;
      nextChunk.split_reason = "merged_heading_forward+" + nextChunk.split_reason;
      nextChunk.merged_small_section_count =
        (nextChunk.merged_small_section_count || 0) + 1;
      nextChunk.merged_small_section_titles = [
        chunk.title,
        ...(nextChunk.merged_small_section_titles || [])
      ];

      continue;
    }

    if (merged.length > 0) {
      const previous = merged[merged.length - 1];

      previous.chunk_text = previous.chunk_text + "\n\n" + chunk.chunk_text;
      previous.split_reason = previous.split_reason + "+merged_small_section";
      previous.merged_small_section_count =
        (previous.merged_small_section_count || 0) + 1;
      previous.merged_small_section_titles = [
        ...(previous.merged_small_section_titles || []),
        chunk.title
      ];

      continue;
    }

    if (index + 1 < chunks.length) {
      const nextChunk = chunks[index + 1];

      nextChunk.chunk_text = chunk.chunk_text + "\n\n" + nextChunk.chunk_text;
      nextChunk.split_reason = "merged_small_section_forward+" + nextChunk.split_reason;
      nextChunk.merged_small_section_count =
        (nextChunk.merged_small_section_count || 0) + 1;
      nextChunk.merged_small_section_titles = [
        chunk.title,
        ...(nextChunk.merged_small_section_titles || [])
      ];

      continue;
    }

    merged.push({
      ...chunk,
      merged_small_section_count: chunk.merged_small_section_count || 0,
      merged_small_section_titles: chunk.merged_small_section_titles || []
    });
  }

  return merged;
}

const chunksByDocument = {};

for (const item of items) {
  const chunk = item.json;
  const documentId = chunk.document_id;

  if (!chunksByDocument[documentId]) {
    chunksByDocument[documentId] = [];
  }

  chunksByDocument[documentId].push(chunk);
}

const output = [];

for (const documentId of Object.keys(chunksByDocument)) {
  const chunks = chunksByDocument[documentId].sort(
    (a, b) => a.chunk_index - b.chunk_index
  );

  const mergedChunks = mergeDocumentChunks(chunks);

  mergedChunks.forEach((chunk, index) => {
    const chunkText = chunk.chunk_text.trim();

    output.push({
      json: {
        ...chunk,
        chunk_id: chunk.document_id + "#chunk-" + index,
        chunk_index: index,
        chunk_text: chunkText,
        chunk_char_count: chunkText.length,
        chunk_word_count: countWords(chunkText),
        tiny_chunk_merge_status:
          chunk.merged_small_section_count > 0 ? "merged" : "not_merged"
      }
    });
  });
}

return output;

