          grouped_section_count: chunk.grouped_section_count || 0,
          grouped_section_titles: (chunk.grouped_section_titles || []).join(" | "),
          ingestion_status: chunk.ingestion_status,
          chunk_status: chunk.chunk_status
        }
      } 
    }; 
  });
